# --------------------------------------------------------------------------
# Transport (Bucket A: session_and_auth + module-level cache)
# --------------------------------------------------------------------------

_SESSION: Optional[requests.Session] = None
_AUTH: Any = None


def _get_session():
    global _SESSION, _AUTH
    if _SESSION is None:
        _SESSION, _AUTH = session_and_auth()
    return _SESSION, _AUTH


def _valet_get(path: str, params: Optional[Dict[str, Any]] = None) -> Any:
    """GET a Valet route and parse JSON. ``path`` is the portion after the
    base, without a trailing /json (added here). Returns None on 404."""
    session, auth = _get_session()
    url = f"{VALET_BASE}/{path}/json"
    resp = session.get(url, params=params or {}, auth=auth, timeout=DEFAULT_TIMEOUT)
    if resp.status_code == 404:
        return None
    if resp.status_code != 200:
        raise BankOfCanadaError(f"Valet {path} -> HTTP {resp.status_code}: "
                                f"{resp.text[:200]}")
    return resp.json()


def _fold(text: str) -> str:
    if not text:
        return ""
    norm = unicodedata.normalize("NFKD", text)
    return "".join(c for c in norm if not unicodedata.combining(c)).casefold()


def _coerce_number(raw: Any) -> Any:
    if raw is None or raw == "":
        return None
    try:
        return float(raw)
    except (TypeError, ValueError):
        return raw


# --------------------------------------------------------------------------
# Discovery — embedded ontology (no network)
# --------------------------------------------------------------------------

def search_series(keyword: str, limit: int = 50) -> List[Dict[str, str]]:
    """Search the embedded series index by name or label (accent/case-
    insensitive; all tokens must match). Returns ``[{name, label}, ...]``."""
    tokens = [_fold(t) for t in keyword.split() if t.strip()]
    out = []
    for name, label in _SERIES.items():
        hay = _fold(name) + " " + _fold(label)
        if all(t in hay for t in tokens):
            out.append({"name": name, "label": label})
            if len(out) >= limit:
                break
    return out


def search_groups(keyword: str, limit: int = 50) -> List[Dict[str, str]]:
    """Search the embedded group index by name or label."""
    tokens = [_fold(t) for t in keyword.split() if t.strip()]
    out = []
    for name, label in _GROUPS.items():
        hay = _fold(name) + " " + _fold(label)
        if all(t in hay for t in tokens):
            out.append({"name": name, "label": label})
            if len(out) >= limit:
                break
    return out


def list_groups(search: Optional[str] = None) -> List[Dict[str, str]]:
    """All embedded groups (optionally filtered by keyword)."""
    if search:
        return search_groups(search, limit=10 ** 9)
    return [{"name": n, "label": l} for n, l in _GROUPS.items()]


def list_catalog() -> List[Dict[str, Any]]:
    """The curated headline catalog (rates / FX / monetary fast path)."""
    return [dict(alias=k, **v) for k, v in CATALOG.items()]


def search_catalog(keyword: str) -> List[Dict[str, Any]]:
    kf = _fold(keyword)
    return [dict(alias=k, **v) for k, v in CATALOG.items()
            if kf in _fold(k) or kf in _fold(v.get("label", ""))]


# --------------------------------------------------------------------------
# On-demand detail (live)
# --------------------------------------------------------------------------

def get_series_detail(name: str) -> Optional[Dict[str, Any]]:
    """Live metadata for a single series (name, label, description)."""
    payload = _valet_get(f"series/{name}")
    if not payload:
        return None
    # /series/{name} returns a single "seriesDetails" object; the
    # observations route uses "seriesDetail" keyed by name.
    det = payload.get("seriesDetails")
    if det:
        return det
    det = payload.get("seriesDetail", {}) or {}
    return det.get(name) or (next(iter(det.values())) if det else None)


def get_group_detail(name: str) -> Optional[Dict[str, Any]]:
    """Live group detail: label, description, and the member series
    (name -> label). Returns ``{name, label, description, series: {...}}``."""
    payload = _valet_get(f"groups/{name}")
    if not payload:
        return None
    gd = payload.get("groupDetails", {})
    members = gd.get("groupSeries", {}) or {}
    return {
        "name": name,
        "label": gd.get("label"),
        "description": gd.get("description"),
        "series": {k: v.get("label") for k, v in members.items()},
    }


# --------------------------------------------------------------------------
# Data (live)
# --------------------------------------------------------------------------

def _period_params(start_date, end_date, recent, recent_weeks,
                   recent_months, recent_years, order_dir) -> Dict[str, Any]:
    params: Dict[str, Any] = {}
    if start_date:
        params["start_date"] = start_date
    if end_date:
        params["end_date"] = end_date
    if recent:
        params["recent"] = recent
    if recent_weeks:
        params["recent_weeks"] = recent_weeks
    if recent_months:
        params["recent_months"] = recent_months
    if recent_years:
        params["recent_years"] = recent_years
    if order_dir:
        params["order_dir"] = order_dir
    return params


def _parse_observations(payload: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    """Parse a Valet observations payload into clean per-series dicts:
    ``[{name, label, description, observations: {date: float}}, ...]``."""
    if not payload:
        return []
    detail = payload.get("seriesDetail", {}) or {}
    names = list(detail.keys())
    rows = payload.get("observations", []) or []
    # Discover series names from observation rows too (robust to ordering).
    for row in rows:
        for k in row:
            if k != "d" and k not in names:
                names.append(k)
    out = []
    for name in names:
        obs: Dict[str, Any] = {}
        for row in rows:
            cell = row.get(name)
            if cell is None:
                continue
            val = cell.get("v") if isinstance(cell, dict) else cell
            obs[row["d"]] = _coerce_number(val)
        det = detail.get(name, {})
        out.append({
            "name": name,
            "label": det.get("label"),
            "description": det.get("description"),
            "observations": obs,
        })
    return out


def _resolve_series_name(name: str) -> str:
    """Resolve a catalog alias to its underlying series name (pass through
    raw names). Raises if the alias is a group."""
    if name in CATALOG:
        meta = CATALOG[name]
        if "series" not in meta:
            raise BankOfCanadaError(
                f"catalog alias {name!r} is a group; use "
                f"get_group_observations({meta.get('group')!r})")
        return meta["series"]
    return name


def get_observations(series: Union[str, Sequence[str]],
                     start_date: Optional[str] = None,
                     end_date: Optional[str] = None,
                     recent: Optional[int] = None,
                     recent_weeks: Optional[int] = None,
                     recent_months: Optional[int] = None,
                     recent_years: Optional[int] = None,
                     order_dir: Optional[str] = None) -> List[Dict[str, Any]]:
    """Fetch observations for one or more series by name or catalog alias.

    Args:
        series: a series name/alias or list thereof (comma-joined for the API).
        start_date / end_date: 'YYYY-MM-DD' bounds (end_date defaults to the
            latest available date when omitted).
        recent / recent_weeks / recent_months / recent_years: relative
            windows (use one; mutually exclusive with start/end_date).
        order_dir: 'asc' or 'desc'.
    """
    if isinstance(series, str):
        names = _resolve_series_name(series)
    else:
        names = ",".join(_resolve_series_name(s) for s in series)
    params = _period_params(start_date, end_date, recent, recent_weeks,
                            recent_months, recent_years, order_dir)
    return _parse_observations(_valet_get(f"observations/{names}", params))


def get_group_observations(group: str,
                           start_date: Optional[str] = None,
                           end_date: Optional[str] = None,
                           recent: Optional[int] = None,
                           recent_weeks: Optional[int] = None,
                           recent_months: Optional[int] = None,
                           recent_years: Optional[int] = None,
                           order_dir: Optional[str] = None) -> List[Dict[str, Any]]:
    """Fetch observations for every series in a group in one call. ``group``
    may be a Valet group name or a catalog group alias."""
    if group in CATALOG and "group" in CATALOG[group]:
        group = CATALOG[group]["group"]
    params = _period_params(start_date, end_date, recent, recent_weeks,
                            recent_months, recent_years, order_dir)
    return _parse_observations(_valet_get(f"observations/group/{group}", params))


def latest(series_or_alias: str) -> Optional[Dict[str, Any]]:
    """Most-recent observation for a series name or catalog alias.

    Returns ``{value, date, series, label}`` or None.
    """
    name = series_or_alias
    if series_or_alias in CATALOG:
        meta = CATALOG[series_or_alias]
        if "series" not in meta:
            raise BankOfCanadaError(
                f"catalog alias {series_or_alias!r} is a group; use "
                f"get_group_observations({meta.get('group')!r})")
        name = meta["series"]
    res = get_observations(name, recent=1)
    if not res or not res[0]["observations"]:
        return None
    s = res[0]
    date, value = next(iter(s["observations"].items()))
    return {"value": value, "date": date, "series": s["name"],
            "label": s["label"]}


# --------------------------------------------------------------------------
# PRISM ergonomics — pandas conversion
# --------------------------------------------------------------------------

def observations_to_dataframe(series: List[Dict[str, Any]], wide: bool = True):
    """Convert parsed observations to a pandas DataFrame.

    Wide (default): one column per series (by name), date as the index.
    Long: one row per (series, date) with name/label/date/value columns.
    """
    try:
        import pandas as pd
    except ImportError as e:  # pragma: no cover
        raise ImportError("observations_to_dataframe requires pandas") from e
    if wide:
        cols = {s["name"]: pd.Series(s["observations"]) for s in series}
        df = pd.DataFrame(cols)
        df.index = pd.to_datetime(df.index, errors="coerce")
        return df.sort_index()
    rows = []
    for s in series:
        for date, val in s["observations"].items():
            rows.append({"name": s["name"], "label": s["label"],
                         "date": date, "value": val})
    return pd.DataFrame(rows)


# --------------------------------------------------------------------------
# Refresh (offline tool — never called from the PRISM sandbox)
# --------------------------------------------------------------------------

def refresh_ontology(*, write_to: Optional[str] = None,
                     verbose: bool = True) -> Dict[str, Any]:
    """Re-harvest the embedded ontology from live Valet (/lists/series +
    /lists/groups), compact to {name: label}, and (if ``write_to`` is this
    module) rewrite the ``_BOC_ONTOLOGY_JSON`` literal in place."""
    def _clean(s):
        # Strip control characters so the embedded JSON literal stays valid.
        return re.sub(r"[\x00-\x1f\x7f]", " ", s or "").strip()

    if verbose:
        print("Fetching /lists/series ...")
    ser_payload = _valet_get("lists/series") or {}
    series = {name: _clean(meta.get("label"))
              for name, meta in (ser_payload.get("series", {}) or {}).items()}
    if verbose:
        print("Fetching /lists/groups ...")
    grp_payload = _valet_get("lists/groups") or {}
    groups = {name: _clean(meta.get("label"))
              for name, meta in (grp_payload.get("groups", {}) or {}).items()}

    import datetime
    ontology = {
        "generated": datetime.datetime.utcnow().strftime("%Y-%m-%d"),
        "series": series,
        "groups": groups,
    }
    if verbose:
        print(f"  series: {len(series)}   groups: {len(groups)}")

    if write_to:
        compact = json.dumps(ontology, separators=(",", ":"), ensure_ascii=False)
        with open(write_to, "r", encoding="utf-8") as f:
            text = f.read()
        pattern = r'_BOC_ONTOLOGY_JSON\s*=\s*r"""(.*?)"""'
        if not re.search(pattern, text, re.DOTALL):
            raise BankOfCanadaError(
                f"Could not locate _BOC_ONTOLOGY_JSON block in {write_to}")
        new_block = f'_BOC_ONTOLOGY_JSON = r"""\n{compact}\n"""'
        text = re.sub(pattern, new_block, text, count=1, flags=re.DOTALL)
        with open(write_to, "w", encoding="utf-8") as f:
            f.write(text)
        if verbose:
            print(f"Wrote refreshed ontology to {write_to} "
                  f"({len(compact):,} chars)")
    return ontology


